/**
 * Generate Alchemy firewall config.
 *
 * Data source: https://www.alchemy.com/docs/how-to-use-api-keys-in-http-headers
 *
 * Alchemy supports API keys or access keys in the Authorization header as a
 * Bearer token.
 */

import { writeOutput } from "./codegen";

const DOCS_URL =
  "https://www.alchemy.com/docs/how-to-use-api-keys-in-http-headers";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Alchemy API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:alchemy",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const alchemyFirewall = {",
    '  name: "alchemy",',
    '  description: "Alchemy API",',
    "  placeholders: {",
    `    ALCHEMY_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://{network}.g.alchemy.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.ALCHEMY_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "    {",
    '      base: "https://api.g.alchemy.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.ALCHEMY_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Alchemy firewall config...");
  const ts = generateTypeScript();
  writeOutput("alchemy", ts, import.meta.dirname);
}
